import React, { useState, useEffect } from "react";
import axios from "axios";
import "../styles/PokemonSearchBar.css"
import { pokemon, setPokemon, 
	pokemonName, setPokemonName, 
	pokemonId, setPokemonId, 
	pokemonData, setPokemonData, 
	pokemonType, setPokemonType, 
	pokemon2ndType, setPokemon2ndType } from "./PokemonInformations";

const PokemonsSearchBar = () => {
	{ pokemon, setPokemon, 
		pokemonName, setPokemonName, 
		pokemonId, setPokemonId, 
		pokemonData, setPokemonData, 
		pokemonType, setPokemonType, 
		pokemon2ndType, setPokemon2ndType } 

	// const getLanguage = async () => {
	// 	const toArray = [];
	// 	try {
	// 		const url = `https://pokeapi.co/api/v2/language/5`;
	// 		const res = await axios.get(url);
	// 		toArray.push(res.data);
	// 		setLanguage(res.data.language)
	// 			} catch (e){
	// 	}
	// };

	const handleChange = (e) => {
		setPokemon(e.target.value.toLowerCase())
		// setLanguage(e.target.value.toLowerCase())
	};

	const handleSubmit= (e) => {
		e.preventDefault();
		getPokemon();
	};

	return (
			<div className="SearchBarContainer">
				<form className="search" onSubmit={handleSubmit}>
					<label>
						<input type = "text"
						onChange = {handleChange}
						placeholder = "N° ou nom du Pokemon" 
						/>
					</label>
				</form>
				{pokemonData.map((data) => {
					return(
						<div className="pokemonContainer"> 
						<img src={data.sprites["front_default"]} alt="Image du Pokemon" className="pokemonImg"/>
						<ul className="pokemonInformationsContainer">
							<li>{pokemonName}</li>
							<li>Pokemon N°{pokemonId}</li>
						</ul>
						<ul className="pokemonStatsContainer">
							<li>
							<h3>Type(s):</h3>
							<p>{pokemonType} {pokemon2ndType}</p>
							</li>
							<li className="stat">
								Taille: {""}{Math.round(data.height * 3.9)}
							</li>
							<li className="stat">
								Poid: {Math.round(data.weight / 4.3)} lbs
								</li>
							</ul>
							</div>
					)
				})}
				</div>
	);
};

export default PokemonsSearchBar;
